parameters.jsonBody:
={{ {
  "contents": [{
    "parts": [{
      "text": "You are a customer relations manager. Output EXACTLY the following message, replacing ONLY the bracketed placeholders with the provided details. Output NOTHING ELSE.

--- DETAILS ---
Customer: " + ($json.body.customerName || "Valued Customer") + "
Trip: " + ($json.body.tripType || "Tour") + "
Driver: " + ($json.body.driverName || "our driver") + "
Notes: " + ($json.body.experienceNotes || "your excellent service") + "
Link: " + ($json.body.reviewLink || "https://g.page/r/xxxx/review") + "

--- EXACT MESSAGE TO OUTPUT ---
Hi [Customer],

Thank you for choosing Manivtha Tours & Travels for your [Trip].

We're delighted to hear that you appreciated [Notes] during your journey with our driver, [Driver].

Your feedback means a lot to us and helps us continue providing excellent service.

We would greatly appreciate it if you could take a moment to leave us a Google review:

[Link]

Thank you for travelling with us, and we look forward to serving you again.

Warm regards,
Manivtha Tours & Travels"
    }]
  }],
  "generationConfig": {
    "temperature": 0.1,
    "maxOutputTokens": 800
  }
} }}
